```typescript
import crypto from 'crypto';
import { db } from './db'; // 假设 db 是你的 postgres 连接池

// 生成邀请
export async function createInvitation(
  teamId: string,
  invitedEmail: string,
  expiresInHours: number = 72
) {
  const token = crypto.randomBytes(32).toString('base64url');
  const expiresAt = new Date(Date.now() + expiresInHours * 60 * 60 * 1000);

  await db.query(
    `INSERT INTO invitations (token, team_id, invited_email, expires_at)
     VALUES ($1, $2, $3, $4)`,
    [token, teamId, invitedEmail, expiresAt]
  );

  return token;
}

// 验证 + 兑现邀请
export async function claimInvitation(token: string, currentUserEmail: string) {
  const result = await db.query(
    `SELECT * FROM invitations 
     WHERE token = $1 AND expires_at > NOW()`,
    [token]
  );

  if (result.rows.length === 0) {
    throw new Error('Invalid or expired invitation');
  }

  const inv = result.rows[0];

  if (inv.used) {
    throw new Error('Invitation already used');
  }

  if (inv.invited_email !== currentUserEmail) {
    throw new Error('Invitation not for this email address');
  }

  // 标记已用，加入团队
  await db.query(
    `UPDATE invitations SET used = true WHERE token = $1`,
    [token]
  );

  await db.query(
    `INSERT INTO team_members (team_id, user_email, added_at)
     VALUES ($1, $2, NOW())`,
    [inv.team_id, currentUserEmail]
  );

  return inv.team_id;
}
```

📁 `/src/schema.sql` (初始化)

```sql
CREATE TABLE invitations (
  token VARCHAR(44) PRIMARY KEY,
  team_id UUID NOT NULL,
  invited_email VARCHAR(255) NOT NULL,
  created_at TIMESTAMP DEFAULT NOW(),
  expires_at TIMESTAMP NOT NULL,
  used BOOLEAN DEFAULT FALSE,

  FOREIGN KEY (team_id) REFERENCES teams(id)
);

CREATE INDEX idx_invitations_team_email ON invitations(team_id, invited_email);
CREATE INDEX idx_invitations_expires ON invitations(expires_at);
```

